<template>
  <div class="home-container">
    <Header :selected-keys="selectedKeys" />

    <div class="main-content">
      <div class="content-container">
        <div class="left-section">
          <div class="illustration">
            <div class="img-container">
              <img
                  src="data:image/jpeg;base64,"
                  :alt="imageAlt"
                  @error="handleImageError"
                  ref="illustrationImg"
              />
              <div v-if="imageError" class="img-mask">
                <!-- {{ imageAlt.charAt(0) }} -->
                {{ imageAlt }}
              </div>
            </div>
          </div>
          <div class="slogan">
            <h2>现代化的前端开发体验</h2>
            <p>基于 Vue 3 + TypeScript + Vite + Ant Design Vue 的前端解决方案</p>
          </div>
        </div>

        <div class="right-section">
          <div class="user-card">
            <div v-if="isLoggedIn" class="user-info">
              <div class="avatar">
                <a-avatar shape="square" :size="{ xs: 64, sm: 64, md: 64, lg: 64, xl: 80, xxl: 95 }" :src="userAvatar" :alt="username">
                  {{ username.charAt(0) }}
                </a-avatar>
              </div>
              <div class="user-details">
                <h3>{{ username }}</h3>
                <a-tag class="user-role">{{ userRole }}</a-tag>
                <p class="user-email">{{ userEmail }}</p>
              </div>
              <div class="user-actions">
                <a-button type="default" class="action-button" @click="goToAdmin">
                  进入管理后台
                </a-button>
                <a-button type="text" danger class="action-button" @click="handleLogout">
                  退出登录
                </a-button>
              </div>
            </div>
            <div v-else class="login-prompt">
              <div class="prompt-content">
                <h3>欢迎访问</h3>
                <p>登录后即可使用完整功能</p>
                <a-button type="primary" class="login-button" @click="goToLogin">
                  登录
                </a-button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <Footer />
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { useRouter } from 'vue-router'
import { message } from 'ant-design-vue'
import { useUserStore } from "@/stores/user";
import type { UserDetailDTO } from "@/types/api"
import { ObjectUtils } from "@/utils";

const selectedKeys = ref<string[]>(['1'])

const router = useRouter()
const illustrationImg = ref<HTMLImageElement | null>(null)
const imageError = ref(false)
const imageAlt = '插图'

const userStore = useUserStore()
const isLoggedIn = ref(false)
const username = ref('访客用户')
const userRole = ref('普通用户')
const userEmail = ref('example@example.com')
const userAvatar = ref('')

const handleImageError = () => {
  imageError.value = true
}

const goToLogin = () => {
  router.push('/login?redirect=/')
}

const goToAdmin = () => {
  router.push('/admin')
}

const handleLogout = async () => {
  await userStore.logout()
  isLoggedIn.value = false
  message.success('已退出登录')
}

onMounted( () => {
  const token = localStorage.getItem('token') || sessionStorage.getItem('token')
  const userInfo = localStorage.getItem('userInfo') || sessionStorage.getItem('userInfo')
  if (token) {
    isLoggedIn.value = true
    if (userInfo != null) {
      const {user, userProfile, userRoles} = JSON.parse(userInfo) as UserDetailDTO
      userAvatar.value = userProfile?.avatarUrl ?? ''
      username.value = user?.username ?? '访客用户'
      // 后端获取角色列表时关联is_primary=1, 返回主角色排第一位
      userRole.value = ObjectUtils.extractValues(userRoles, 'roleName')[0] ?? '普通用户'
      userEmail.value = userProfile?.email ?? 'example@example.com'
    }
  }
})
</script>

